#### 2. Rule Evaluation Layer (Service Layer)

Modify the service layer to include severity levels and evidence references in alerts:

```python
from dal import FhirDal

class CdsService:
    def __init__(self, base_url):
        self.dal = FhirDal(base_url)

    def fetch_medication_requests(self, patient_id, access_token):
        return self.dal.get_medication_requests(patient_id, access_token)

    def fetch_medication_statements(self, patient_id, access_token):
        return self.dal.get_medication_statements(patient_id, access_token)

    def fetch_vital_signs(self, patient_id, access_token):
        return self.dal.get_vital_signs(patient_id, access_token)

    def fetch_lab_results(self, patient_id, access_token):
        return self.dal.get_lab_results(patient_id, access_token)

    def evaluate_sepsis_risk(self, vital_signs, lab_results):
        # Example logic for evaluating sepsis risk
        if any(reading['valueQuantity']['value'] > 100 for reading in vital_signs if 'heartRate' in reading['code']['coding'][0]['display']):
            return True

        if any(result['valueQuantity']['value'] > 2.0 for result in lab_results if 'serumCreatinine' in result['code']['coding'][0]['display']):
            return True

        return False

    def evaluate_aki_risk(self, lab_results):
        # Example logic for evaluating AKI risk
        recent_results = [result for result in lab_results if (datetime.now() - result['effectiveDateTime']).days <= 7]

        if len(recent_results) < 2:
            return False

        baseline_creatinine = min([result['valueQuantity']['value'] for result in recent_results])
        latest_creatinine = max([result['valueQuantity']['value'] for result in recent_results])

        if (latest_creatinine - baseline_creatinine) / baseline_creatinine >= 0.3:
            return True

        return False

    def generate_alert(self, patient_id, alert_type, severity_level, evidence_references):
        # Example structure of an alert
        alert = {
            "patient_id": patient_id,
            "alert_type": alert_type,
            "severity_level": severity_level,
            "evidence_references": evidence_references
        }

        return alert

    def evaluate_and_generate_alerts(self, patient_id, access_token):
        vital_signs = self.fetch_vital_signs(patient_id, access_token)
        lab_results = self.fetch_lab_results(patient_id, access_token)

        sepsis_risk = self.evaluate_sepsis_risk(vital_signs, lab_results)
        aki_risk = self.evaluate_aki_risk(lab_results)

        alerts = []

        if sepsis_risk:
            alert = self.generate_alert(patient_id, "sepsis", "CRITICAL", ["https://example.com/guideline/sepsis"])
            alerts.append(alert)

        if aki_risk:
            alert = self.generate_alert(patient_id, "aki", "WARNING", ["https://example.com/guideline/aki"])
            alerts.append(alert)

        return alerts
```

