from dal import FhirDal

class CdsService:
    def __init__(self, base_url):
        self.dal = FhirDal(base_url)

    def fetch_medication_requests(self, patient_id, access_token):
        return self.dal.get_medication_requests(patient_id, access_token)

    def fetch_medication_statements(self, patient_id, access_token):
        return self.dal.get_medication_statements(patient_id, access_token)

    def fetch_allergies(self, patient_id, access_token):
        return self.dal.get_allergies(patient_id, access_token)

    def evaluate_ddi_rules(self, medications):
        # Example logic for evaluating DDI rules
        ddis = []

        for i in range(len(medications)):
            for j in range(i + 1, len(medications)):
                drug1_code = medications[i]['rxnorm_code']
                drug2_code = medications[j]['rxnorm_code']

                if evaluate_ddi_rule(drug1_code, drug2_code):
                    ddis.append({
                        'drug1': drug1_code,
                        'drug2': drug2_code,
                        'severity': 'WARNING',
                        'description': f'DDI between {medications[i]["name"]} and {medications[j]["name"]}'
                    })

        return ddis

    def evaluate_allergy_rules(self, medications, allergies):
        # Example logic for evaluating allergy rules
        allergic_reactions = []

        for medication in medications:
            drug_code = medication['rxnorm_code']

            for allergy in allergies.get('entry', []):
                if 'resource' in allergy and 'code' in allergy['resource']:
                    allergy_code = allergy['resource']['code'].get('coding', [{}])[0].get('code')

                    if evaluate_allergy_rule(drug_code, allergy_code):
                        allergic_reactions.append({
                            'drug': drug_code,
                            'allergen': allergy_code,
                            'severity': 'CRITICAL',
                            'description': f'Allergic reaction to {medication["name"]}'
                        })

        return allergic_reactions

    def evaluate_and_generate_alerts(self, patient_id, access_token):
        medications = self.fetch_medication_requests(patient_id, access_token)
        allergies = self.fetch_allergies(patient_id, access_token)

        ddis = self.evaluate_ddi_rules(medications['entry'])
        allergic_reactions = self.evaluate_allergy_rules(medications['entry'], allergies)

        alerts = []

        for ddi in ddis:
            alert = {
                'patient_id': patient_id,
                'alert_type': "DDI",
                'severity_level': ddi['severity'],
                'evidence_references': [ddi['description']]
            }

            alerts.append(alert)

        for reaction in allergic_reactions:
            alert = {
                'patient_id': patient_id,
                'alert_type': "Allergy",
                'severity_level': reaction['severity'],
                'evidence_references': [reaction['description']]
            }

            alerts.append(alert)

        return alerts
