    icd10_suggestions = db_session.query(ICD10Suggestion).filter_by(patient_id=patient_id).all()

    # Combine and present to clinician
    combined_data = {
        'alerts': alerts,
        'icd10_suggestions': [s.to_dict() for s in icd10_suggestions]
    }

    return combined_data

